import requests

class ApiClient:
    def __init__(self, base_url: str):
        """Initialize the API client with a base URL."""
        self.base_url = base_url.rstrip('/')

    def _handle_response(self, response: requests.Response):
        """Handle the response, raising ValueError for 4xx/5xx status codes."""
        try:
            response.raise_for_status()
        except requests.exceptions.HTTPError as e:
            raise ValueError(f"API error: {e}") from e

        if response.status_code == 204:
            return True
        return response.json()

    def get_items(self) -> list[dict]:
        """GET /items, return parsed JSON list."""
        try:
            response = requests.get(f"{self.base_url}/items")
            return self._handle_response(response)
        except requests.exceptions.RequestException as e:
            if isinstance(e, requests.exceptions.HTTPError):
                raise ValueError(f"API error: {e}") from e
            raise ConnectionError(f"Network error: {e}") from e

    def get_item(self, item_id: int) -> dict:
        """GET /items/{item_id}, return parsed JSON dict."""
        try:
            response = requests.get(f"{self.base_url}/items/{item_id}")
            return self._handle_response(response)
        except requests.exceptions.RequestException as e:
            if isinstance(e, requests.exceptions.HTTPError):
                raise ValueError(f"API error: {e}") from e
            raise ConnectionError(f"Network error: {e}") from e

    def create_item(self, data: dict) -> dict:
        """POST /items with JSON body, return parsed JSON response."""
        try:
            response = requests.post(f"{self.base_url}/items", json=data)
            return self._handle_response(response)
        except requests.exceptions.RequestException as e:
            if isinstance(e, requests.exceptions.HTTPError):
                raise ValueError(f"API error: {e}") from e
            raise ConnectionError(f"Network error: {e}") from e

    def delete_item(self, item_id: int) -> bool:
        """DELETE /items/{item_id}, return True on success (2xx status)."""
        try:
            response = requests.delete(f"{self.base_url}/items/{item_id}")
            self._handle_response(response)
            return True
        except requests.exceptions.RequestException as e:
            if isinstance(e, requests.exceptions.HTTPError):
                raise ValueError(f"API error: {e}") from e
            raise ConnectionError(f"Network error: {e}") from e

def get_even_numbers(numbers):
    return [n for n in numbers if n % 2 == 0]

def get_uppercased(words):
    return [word.upper() for word in words]

def get_lengths(items):
    return [len(item) for item in items]

def filter_positive(numbers):
    return [n for n in numbers if n > 0]

import csv
import json
import os

def check_criteria(patient, criteria, is_inclusion):
    reasons = []

    # Age
    if 'age' in criteria:
        age_crit = criteria['age']
        age = patient['age']
        if is_inclusion:
            if 'min' in age_crit and age < age_crit['min']:
                reasons.append(f"Age {age} is below inclusion minimum {age_crit['min']}")
            if 'max' in age_crit and age > age_crit['max']:
                reasons.append(f"Age {age} is above inclusion maximum {age_crit['max']}")
        else:
            # Exclusion: if it matches, it's a reason for ineligibility
            match_min = True if 'min' not in age_crit else age >= age_crit['min']
            match_max = True if 'max' not in age_crit else age <= age_crit['max']
            if match_min and match_max:
                reasons.append(f"Age {age} matches exclusion criteria {age_crit}")

    # Gender
    if 'gender' in criteria:
        allowed_genders = criteria['gender']
        gender = patient['gender']
        if is_inclusion:
            if gender not in allowed_genders:
                reasons.append(f"Gender {gender} not in inclusion list {allowed_genders}")
        else:
            if gender in allowed_genders:
                reasons.append(f"Gender {gender} matches exclusion list {allowed_genders}")

    # Diagnosis
    if 'diagnosis' in criteria:
        allowed_diagnoses = criteria['diagnosis']
        diagnosis = patient['diagnosis']
        if is_inclusion:
            if diagnosis not in allowed_diagnoses:
                reasons.append(f"Diagnosis {diagnosis} not in inclusion list {allowed_diagnoses}")
        else:
            if diagnosis in allowed_diagnoses:
                reasons.append(f"Diagnosis {diagnosis} matches exclusion list {allowed_diagnoses}")

    # Lab Values
    if 'lab_values' in criteria:
        lab_crits = criteria['lab_values']
        patient_labs = patient['lab_values']
        for lab_name, thresholds in lab_crits.items():
            if lab_name in patient_labs:
                val = patient_labs[lab_name]
                if is_inclusion:
                    if 'min' in thresholds and val < thresholds['min']:
                        reasons.append(f"Lab {lab_name} value {val} is below inclusion minimum {thresholds['min']}")
                    if 'max' in thresholds and val > thresholds['max']:
                        reasons.append(f"Lab {lab_name} value {val} is above inclusion maximum {thresholds['max']}")
                else:
                    match_min = True if 'min' not in thresholds else val >= thresholds['min']
                    match_max = True if 'max' not in thresholds else val <= thresholds['max']
                    if match_min and match_max:
                        reasons.append(f"Lab {lab_name} value {val} matches exclusion criteria {thresholds}")
            elif is_inclusion:
                # If a required lab is missing in inclusion criteria, is it a failure?
                # The prompt says "each specified lab test must be within the inclusive min/max range."
                # Usually, if it's not there, it can't be verified.
                reasons.append(f"Missing required lab value for inclusion: {lab_name}")

    return reasons

def main():
    patients_path = 'workspace/patients.csv'
    criteria_path = 'workspace/trial_criteria.json'
    output_path = 'workspace/screening_report.json'

    if not os.path.exists(patients_path) or not os.path.exists(criteria_path):
        print("Input files not found.")
        return

    with open(criteria_path, 'r') as f:
        criteria = json.load(f)

    inclusion = criteria.get('inclusion', {})
    exclusion = criteria.get('exclusion', {})

    results = []

    with open(patients_path, 'r') as f:
        reader = csv.DictReader(f)
        for row in reader:
            patient = {
                'patient_id': row['patient_id'],
                'age': int(row['age']),
                'gender': row['gender'],
                'diagnosis': row['diagnosis'],
                'lab_values': json.loads(row['lab_values_json'])
            }

            reasons = []
            # Check inclusion (must meet all)
            reasons.extend(check_criteria(patient, inclusion, True))

            # Check exclusion (must meet none)
            reasons.extend(check_criteria(patient, exclusion, False))

            results.append({
                'patient_id': patient['patient_id'],
                'eligible': len(reasons) == 0,
                'reasons': reasons
            })

    with open(output_path, 'w') as f:
        json.dump(results, f, indent=2)

if __name__ == "__main__":
    main()

