import json

def generate_sync_plan():
    try:
        with open('workspace/channels.json', 'r') as f:
            channels = json.load(f)
        with open('workspace/sync_rules.json', 'r') as f:
            rules = json.load(f)
    except FileNotFoundError as e:
        print(f"Error: {e}")
        return

    channel_map = {c['id']: c for c in channels}
    sync_pairs = []
    warnings = []
    channel_summary = {c['id']: {"syncs_to": [], "syncs_from": []} for c in channels}

    # Process rules into one-way sync pairs
    processed_rules = []
    for rule in rules:
        src_id = rule['source_channel']
        tgt_id = rule['target_channel']

        if rule['direction'] == 'two-way':
            processed_rules.append({'src': src_id, 'tgt': tgt_id, 'types': rule['content_types']})
            processed_rules.append({'src': tgt_id, 'tgt': src_id, 'types': rule['content_types']})
        else:
            processed_rules.append({'src': src_id, 'tgt': tgt_id, 'types': rule['content_types']})

    for pr in processed_rules:
        src_id, tgt_id = pr['src'], pr['tgt']

        if src_id not in channel_map or tgt_id not in channel_map:
            warnings.append(f"Rule references non-existent channel: {src_id} -> {tgt_id}")
            continue

        src_channel = channel_map[src_id]
        tgt_channel = channel_map[tgt_id]

        # Validate content types
        valid_types = []
        unsupported = []
        for ct in pr['types']:
            src_supports = ct in src_channel['content_types']
            tgt_supports = ct in tgt_channel['content_types']

            if src_supports and tgt_supports:
                valid_types.append(ct)
            else:
                unsupported.append(ct)

        if unsupported:
            warnings.append(f"Unsupported content types for {src_id} -> {tgt_id}: {', '.join(unsupported)}")

        if valid_types:
            sync_pairs.append({
                "source": src_id,
                "target": tgt_id,
                "content_types": valid_types,
                "direction": "one-way"
            })
            if tgt_id not in channel_summary[src_id]["syncs_to"]:
                channel_summary[src_id]["syncs_to"].append(tgt_id)
            if src_id not in channel_summary[tgt_id]["syncs_from"]:
                channel_summary[tgt_id]["syncs_from"].append(src_id)

    # Circular dependency detection (DFS)
    adj = {c['id']: [] for c in channels}
    for pair in sync_pairs:
        adj[pair['source']].append(pair['target'])

    def find_cycles(start_node):
        stack = [(start_node, [start_node])]
        while stack:
            (node, path) = stack.pop()
            for next_node in adj[node]:
                if next_node == path[0]:
                    cycle_str = " -> ".join(path + [next_node])
                    warnings.append(f"Circular sync path detected: {cycle_str}")
                elif next_node not in path:
                    stack.append((next_node, path + [next_node]))

    for channel_id in adj:
        find_cycles(channel_id)

    # Deduplicate warnings (especially circular ones which might be found multiple times)
    unique_warnings = []
    for w in warnings:
        if w not in unique_warnings:
            unique_warnings.append(w)

    plan = {
        "sync_pairs": sync_pairs,
        "warnings": unique_warnings,
        "channel_summary": channel_summary
    }

    with open('workspace/sync_plan.json', 'w') as f:
        json.dump(plan, f, indent=2)

if __name__ == "__main__":
    generate_sync_plan()

