from collections import defaultdict

def classify_sentiment():
    positive_words = {'good', 'great', 'excellent', 'amazing', 'love', 'wonderful', 'best', 'fantastic', 'perfect', 'nice'}
    negative_words = {'bad', 'terrible', 'awful', 'worst', 'hate', 'poor', 'disappointing', 'boring', 'slow', 'ugly'}

    product_stats = defaultdict(lambda: {
        'total_reviews': 0,
        'positive_reviews': 0,
        'negative_reviews': 0,
        'neutral_reviews': 0,
        'total_sentiment_score': 0.0
    })

    try:
        with open('workspace/reviews.csv', mode='r', encoding='utf-8') as csvfile:
            reader = csv.DictReader(csvfile)
            for row in reader:
                product = row['product']
                text = row['text'].lower()

                # Tokenize text to find words (case-insensitive already handled by .lower())
                # Using regex to find words to match the keyword list accurately
                words = re.findall(r'\b\w+\b', text)

                pos_count = sum(1 for word in words if word in positive_words)
                neg_count = sum(1 for word in words if word in negative_words)

                sentiment_score = pos_count - neg_count

                stats = product_stats[product]
                stats['total_reviews'] += 1
                stats['total_sentiment_score'] += sentiment_score

                if sentiment_score > 0:
                    stats['positive_reviews'] += 1
                elif sentiment_score < 0:
                    stats['negative_reviews'] += 1
                else:
                    stats['neutral_reviews'] += 1

        # Prepare final output
        dashboard = {}
        for product, stats in product_stats.items():
            dashboard[product] = {
                'total_reviews': stats['total_reviews'],
                'positive_reviews': stats['positive_reviews'],
                'negative_reviews': stats['negative_reviews'],
                'neutral_reviews': stats['neutral_reviews'],
                'average_sentiment_score': stats['total_sentiment_score'] / stats['total_reviews']
            }

        with open('workspace/sentiment_dashboard.json', 'w', encoding='utf-8') as jsonfile:
            json.dump(dashboard, jsonfile, indent=4)

    except FileNotFoundError:
        print("Error: workspace/reviews.csv not found.")

if __name__ == "__main__":
    classify_sentiment()

import json
import os

def generate_sync_plan():
    channels_path = 'workspace/channels.json'
    rules_path = 'workspace/sync_rules.json'
    output_path = 'workspace/sync_plan.json'

    if not os.path.exists(channels_path) or not os.path.exists(rules_path):
        print("Input files missing")
        return

    with open(channels_path, 'r') as f:
        channels = json.load(f)
    with open(rules_path, 'r') as f:
        rules = json.load(f)

    channel_map = {c['id']: c for c in channels}
    sync_pairs = []
    warnings = []
    channel_summary = {c['id']: {"syncs_to": [], "syncs_from": []} for c in channels}

    # Process rules into one-way sync pairs
    processed_rules = []
    for rule in rules:
        src_id = rule['source_channel']
        tgt_id = rule['target_channel']

        if rule['direction'] == 'two-way':
            processed_rules.append({'src': src_id, 'tgt': tgt_id, 'types': rule['content_types']})
            processed_rules.append({'src': tgt_id, 'tgt': src_id, 'types': rule['content_types']})
        else:
            processed_rules.append({'src': src_id, 'tgt': tgt_id, 'types': rule['content_types']})

    for pr in processed_rules:
        src_id, tgt_id = pr['src'], pr['tgt']

        if src_id not in channel_map or tgt_id not in channel_map:
            warnings.append(f"Rule references non-existent channel: {src_id} -> {tgt_id}")
            continue

        src_channel = channel_map[src_id]
        tgt_channel = channel_map[tgt_id]

        valid_types = []
        unsupported = []
        for ct in pr['types']:
            src_supports = ct in src_channel['content_types']
            tgt_supports = ct in tgt_channel['content_types']

            if src_supports and tgt_supports:
                valid_types.append(ct)
            else:
                unsupported.append(ct)

        if unsupported:
            warnings.append(f"Unsupported content types for {src_id} -> {tgt_id}: {', '.join(unsupported)}")

        if valid_types:
            sync_pairs.append({
                "source": src_id,
                "target": tgt_id,
                "content_types": valid_types,
                "direction": "one-way"
            })
            if tgt_id not in channel_summary[src_id]["syncs_to"]:
                channel_summary[src_id]["syncs_to"].append(tgt_id)
            if src_id not in channel_summary[tgt_id]["syncs_from"]:
                channel_summary[tgt_id]["syncs_from"].append(src_id)

    # Circular dependency detection
    adj = {c['id']: [] for c in channels}
    for pair in sync_pairs:
        adj[pair['source']].append(pair['target'])

    def find_all_cycles(adj):
        cycles = []
        def visit(node, path):
            for neighbor in adj[node]:
                if neighbor in path:
                    # Found a cycle
                    idx = path.index(neighbor)
                    cycle = path[idx:] + [neighbor]
                    cycles.append(cycle)
                else:
                    visit(neighbor, path + [neighbor])

        for node in adj:
            visit(node, [node])
        return cycles

    raw_cycles = find_all_cycles(adj)

    # Normalize and deduplicate cycles
    unique_cycles = set()
    for cycle in raw_cycles:
        # To deduplicate A-B-A and B-A-B, or A-B-C-A and B-C-A-B
        # We find the minimum element and rotate the cycle to start with it
        nodes = cycle[:-1]
        min_node = min(nodes)
        min_idx = nodes.index(min_node)
        rotated = nodes[min_idx:] + nodes[:min_idx]
        unique_cycles.add(tuple(rotated))

    for cycle in sorted(list(unique_cycles)):
        cycle_str = " -> ".join(list(cycle) + [cycle[0]])
        warnings.append(f"Circular sync path detected: {cycle_str}")

    plan = {
        "sync_pairs": sync_pairs,
        "warnings": warnings,
        "channel_summary": channel_summary
    }

    with open(output_path, 'w') as f:
        json.dump(plan, f, indent=2)

if __name__ == "__main__":
    generate_sync_plan()

