python3 -c '
import json
import yaml
import os

def parse_requirements(file_path):
    with open(file_path, "r") as f:
        content = f.read()

    blocks = content.strip().split("\n\n")
    endpoints = []
    for block in blocks:
        lines = block.split("\n")
        data = {}
        current_key = None
        schema_buffer = []

        for line in lines:
            if line.startswith("Endpoint:"):
                data["endpoint"] = line.split(":", 1)[1].strip()
            elif line.startswith("Method:"):
                data["method"] = line.split(":", 1)[1].strip()
            elif line.startswith("RequestSchema:"):
                current_key = "request_schema"
            elif line.startswith("ResponseSchema:"):
                current_key = "response_schema"
            else:
                schema_buffer.append(line)

            if current_key and line.strip() == "}":
                data[current_key] = json.loads("\n".join(schema_buffer))
                schema_buffer = []
                current_key = None
        endpoints.append(data)
    return endpoints

def generate_openapi(endpoints):
    spec = {
        "openapi": "3.0.0",
        "info": {"title": "Generated API", "version": "1.0.0"},
        "paths": {}
    }

    for ep in endpoints:
        path = ep["endpoint"]
        method = ep["method"].lower()

        if path not in spec["paths"]:
            spec["paths"][path] = {}

        # Handle path parameters
        if "{" in path:
            params = []
            import re
            path_vars = re.findall(r"\{(\w+)\}", path)
            for var in path_vars:
                params.append({
                    "name": var,
                    "in": "path",
                    "required": True,
                    "schema": {"type": "string"}
                })
            spec["paths"][path]["parameters"] = params

        op = {
            "responses": {
                "200": {
                    "description": "Successful response",
                    "content": {
                        "application/json": {
                            "schema": ep["response_schema"]
                        }
                    }
                }
            }
        }

        if ep.get("request_schema") and ep["request_schema"] != {}:
            op["requestBody"] = {
                "content": {
                    "application/json": {
                        "schema": ep["request_schema"]
                    }
                }
            }

        spec["paths"][path][method] = op

    return spec

def generate_flask(endpoints):
    code = ["from flask import Flask, request, jsonify", "", "app = Flask(__name__)", ""]

    # Group by endpoint
    grouped = {}
    for ep in endpoints:
        path = ep["endpoint"]
        if path not in grouped:
            grouped[path] = []
        grouped[path].append(ep)

    for path, ops in grouped.items():
        flask_path = path.replace("{", "<").replace("}", ">")
        methods = [op["method"] for op in ops]
        func_name = path.strip("/").replace("/", "_").replace("{", "").replace("}", "") or "index"

        code.append(f"@app.route(\"{flask_path}\", methods={methods})")

        # Extract path params for function signature
        import re
        path_vars = re.findall(r"\{(\w+)\}", path)
        sig = ", ".join(path_vars)

        code.append(f"def {func_name}_handler({sig}):")
        code.append("    if request.is_json:")
        code.append("        data = request.get_json()")
        code.append("    return jsonify({\"message\": \"placeholder\"}), 200")
        code.append("")

    code.append("if __name__ == \"__main__\":")
    code.append("    app.run(debug=True)")

    return "\n".join(code)

def generate_summary(endpoints):
    distinct_endpoints = len(set(ep["endpoint"] for ep in endpoints))
    methods_count = {}
    for ep in endpoints:
        m = ep["method"]
        methods_count[m] = methods_count.get(m, 0) + 1

    return {
        "endpoint_count": distinct_endpoints,
        "methods": methods_count
    }

# Main execution
req_path = "workspace/api_requirements.txt"
endpoints = parse_requirements(req_path)

# OpenAPI
openapi_spec = generate_openapi(endpoints)
with open("workspace/openapi.yaml", "w") as f:
    yaml.dump(openapi_spec, f, sort_keys=False)

# Flask
flask_app = generate_flask(endpoints)
with open("workspace/app.py", "w") as f:
    f.write(flask_app)

# Summary
summary = generate_summary(endpoints)
with open("workspace/api_summary.json", "w") as f:
    json.dump(summary, f, indent=2)
'

