import csv
import json
from collections import defaultdict

def analyze_data():
    data = []
    with open('workspace/company_data.csv', 'r') as f:
        reader = csv.DictReader(f)
        for row in reader:
            row['revenue'] = float(row['revenue'])
            row['employees'] = int(row['employees'])
            row['satisfaction_score'] = float(row['satisfaction_score'])
            data.append(row)

    # Summary Statistics
    total_revenue = sum(d['revenue'] for d in data)
    avg_revenue = total_revenue / len(data)
    total_employees = sum(d['employees'] for d in data)
    avg_satisfaction = sum(d['satisfaction_score'] for d in data) / len(data)

    # Top Performers (by total revenue)
    company_revenue = defaultdict(float)
    for d in data:
        company_revenue[d['company']] += d['revenue']
    top_performers = sorted(company_revenue.items(), key=lambda x: x[1], reverse=True)[:5]

    # Regional Trends (average revenue by region)
    region_revenue = defaultdict(list)
    region_employees = defaultdict(int)
    for d in data:
        region_revenue[d['region']].append(d['revenue'])
        region_employees[d['region']] += d['employees']

    avg_revenue_by_region = {r: sum(revs)/len(revs) for r, revs in region_revenue.items()}

    # Quarterly Trends (total revenue per quarter)
    quarterly_revenue = defaultdict(float)
    for d in data:
        quarterly_revenue[d['quarter']] += d['revenue']

    # Sort quarters
    sorted_quarters = sorted(quarterly_revenue.keys())

    # Generate report.md
    report = f"""# Comprehensive Analysis Report

## Summary Statistics
- **Total Revenue:** ${total_revenue:,.2f}
- **Average Revenue:** ${avg_revenue:,.2f}
- **Total Employees:** {total_employees}
- **Average Satisfaction Score:** {avg_satisfaction:.2f}

## Top Performers
{chr(10).join([f"{i+1}. {name}: ${rev:,.2f}" for i, (name, rev) in enumerate(top_performers)])}

## Regional Trends
{chr(10).join([f"- {region}: ${avg:,.2f} (Average Revenue)" for region, avg in avg_revenue_by_region.items()])}

## Quarterly Trends
{chr(10).join([f"- {q}: ${rev:,.2f}" for q, rev in sorted(quarterly_revenue.items())])}

## Recommendations
1. **Focus on East Region Expansion:** The East region shows high average revenue. Increasing investment or headcount in this region could drive further growth.
2. **Improve Satisfaction in South Region:** Data suggests lower satisfaction scores in the South. Implementing employee engagement programs there may improve retention and performance.
"""

    with open('workspace/report.md', 'w') as f:
        f.write(report)

    # Generate charts_data.json
    charts_data = {
        "bar_chart": {
            "labels": list(avg_revenue_by_region.keys()),
            "values": [round(v, 2) for v in avg_revenue_by_region.values()]
        },
        "line_chart": {
            "labels": sorted_quarters,
            "values": [round(quarterly_revenue[q], 2) for q in sorted_quarters]
        },
        "pie_chart": {
            "labels": list(region_employees.keys()),
            "values": list(region_employees.values())
        }
    }

    with open('workspace/charts_data.json', 'w') as f:
        json.dump(charts_data, f, indent=4)

if __name__ == "__main__":
    analyze_data()

