def find_duplicates(items):
    """Finds all values that appear more than once."""
    seen = set()
    duplicates = set()
    for item in items:
        if item in seen:
            duplicates.add(item)
        else:
            seen.add(item)
    return sorted(list(duplicates))

def find_common_elements(list_a, list_b):
    """Finds elements in both lists."""
    return sorted(list(set(list_a) & set(list_b)))

def count_unique(items):
    """Counts distinct elements."""
    return len(set(items))

def has_pair_with_sum(numbers, target):
    """Checks if any two numbers sum to target."""
    seen = set()
    for num in numbers:
        complement = target - num
        if complement in seen:
            return True
        seen.add(num)
    return False

import json
import difflib

def compare_documents(v1_path, v2_path, output_path):
    with open(v1_path, 'r') as f:
        v1_lines = f.readlines()
    with open(v2_path, 'r') as f:
        v2_lines = f.readlines()

    # Remove trailing newlines for comparison
    v1_lines_clean = [line.rstrip('\n') for line in v1_lines]
    v2_lines_clean = [line.rstrip('\n') for line in v2_lines]

    matcher = difflib.SequenceMatcher(None, v1_lines_clean, v2_lines_clean)

    added = []
    removed = []
    modified = []
    unchanged_count = 0

    for tag, i1, i2, j1, j2 in matcher.get_opcodes():
        if tag == 'equal':
            unchanged_count += (i2 - i1)
        elif tag == 'replace':
            # difflib 'replace' can be a mix of modified lines and additions/removals
            # if the number of lines matches, we treat them as modified
            # otherwise we try to pair them or treat as separate add/remove
            len1 = i2 - i1
            len2 = j2 - j1
            common_len = min(len1, len2)

            for k in range(common_len):
                modified.append({
                    "line_number_v1": i1 + k + 1,
                    "line_number_v2": j1 + k + 1,
                    "old_content": v1_lines_clean[i1 + k],
                    "new_content": v2_lines_clean[j1 + k]
                })

            if len1 > len2:
                for k in range(common_len, len1):
                    removed.append({
                        "line_number": i1 + k + 1,
                        "content": v1_lines_clean[i1 + k]
                    })
            elif len2 > len1:
                for k in range(common_len, len2):
                    added.append({
                        "line_number": j1 + k + 1,
                        "content": v2_lines_clean[j1 + k]
                    })
        elif tag == 'delete':
            for k in range(i1, i2):
                removed.append({
                    "line_number": k + 1,
                    "content": v1_lines_clean[k]
                })
        elif tag == 'insert':
            for k in range(j1, j2):
                added.append({
                    "line_number": k + 1,
                    "content": v2_lines_clean[k]
                })

    result = {
        "added": added,
        "removed": removed,
        "modified": modified,
        "unchanged_count": unchanged_count,
        "summary": {
            "total_added": len(added),
            "total_removed": len(removed),
            "total_modified": len(modified),
            "total_unchanged": unchanged_count
        }
    }

    with open(output_path, 'w') as f:
        json.dump(result, f, indent=2)

if __name__ == "__main__":
    compare_documents('workspace/v1.txt', 'workspace/v2.txt', 'workspace/changes.json')

