import sys
import re

def is_numeric(s):
    s = s.strip()
    if not s:
        return False
    try:
        float(s)
        return True
    except ValueError:
        return False

def format_table(lines):
    if not lines:
        return []

    # Parse rows and cells
    rows = []
    for line in lines:
        # Remove leading/trailing pipes and split
        content = line.strip()
        if content.startswith('|'):
            content = content[1:]
        if content.endswith('|'):
            content = content[:-1]
        cells = [c.strip() for c in content.split('|')]
        rows.append(cells)

    if len(rows) < 2:
        return lines

    # Identify header, separator, and data rows
    header = rows[0]
    # rows[1] is the separator row, we'll recreate it
    data_rows = rows[2:]

    num_cols = len(header)
    col_widths = [len(h) for h in header]

    # Update widths based on data
    for row in data_rows:
        for i in range(min(len(row), num_cols)):
            col_widths[i] = max(col_widths[i], len(row[i]))

    # Determine alignment (numeric check on data rows only)
    alignments = [] # True for right (numeric), False for left
    for i in range(num_cols):
        is_col_numeric = True
        if not data_rows:
            is_col_numeric = False
        else:
            for row in data_rows:
                if i < len(row) and row[i]:
                    if not is_numeric(row[i]):
                        is_col_numeric = False
                        break
                elif i >= len(row):
                    # Missing cell in a row, treat as non-numeric or just ignore? 
                    # Usually, if it's empty it's fine, but let's be safe.
                    pass
        alignments.append(is_col_numeric)

    # Build formatted rows
    formatted_lines = []

    # Header
    header_str = "|"
    for i in range(num_cols):
        val = header[i]
        width = col_widths[i]
        header_str += f" {val.ljust(width)} |"
    formatted_lines.append(header_str)

    # Separator
    sep_str = "|"
    for i in range(num_cols):
        width = col_widths[i]
        if alignments[i]:
            sep_str += " " + "-" * (width - 1) + ": |"
        else:
            sep_str += " " + "-" * width + " |"
    formatted_lines.append(sep_str)

    # Data
    for row in data_rows:
        row_str = "|"
        for i in range(num_cols):
            val = row[i] if i < len(row) else ""
            width = col_widths[i]
            if alignments[i]:
                row_str += f" {val.rjust(width)} |"
            else:
                row_str += f" {val.ljust(width)} |"
        formatted_lines.append(row_str)

    return formatted_lines

def main():
    with open('workspace/input.md', 'r') as f:
        lines = f.readlines()

    output = []
    table_buffer = []
    in_table = False

    for line in lines:
        stripped = line.strip()
        # Simple table detection: starts and ends with | or contains | and next line is separator
        is_table_line = stripped.startswith('|') and stripped.endswith('|')

        if is_table_line:
            in_table = True
            table_buffer.append(line)
        else:
            if in_table:
                output.extend(format_table(table_buffer))
                table_buffer = []
                in_table = False
            output.append(line.rstrip('\n'))

    if in_table:
        output.extend(format_table(table_buffer))

    with open('workspace/formatted.md', 'w') as f:
        f.write('\n'.join(output) + '\n')

if __name__ == "__main__":
    main()

