import sys
import re

def is_numeric(s):
    s = s.strip()
    if not s:
        return False
    try:
        float(s)
        return True
    except ValueError:
        return False

def format_table(lines):
    if not lines:
        return []

    rows = []
    for line in lines:
        content = line.strip()
        if content.startswith('|'):
            content = content[1:]
        if content.endswith('|'):
            content = content[:-1]
        cells = [c.strip() for c in content.split('|')]
        rows.append(cells)

    if len(rows) < 2:
        return lines

    header = rows[0]
    data_rows = rows[2:] if len(rows) > 2 else []

    num_cols = len(header)
    col_widths = [len(h) for h in header]

    for row in data_rows:
        for i in range(min(len(row), num_cols)):
            col_widths[i] = max(col_widths[i], len(row[i]))

    alignments = [] 
    for i in range(num_cols):
        is_col_numeric = True
        has_data = False
        for row in data_rows:
            if i < len(row) and row[i]:
                has_data = True
                if not is_numeric(row[i]):
                    is_col_numeric = False
                    break
        alignments.append(is_col_numeric and has_data)

    formatted_lines = []

    header_str = "|"
    for i in range(num_cols):
        val = header[i]
        width = col_widths[i]
        header_str += f" {val.ljust(width)} |"
    formatted_lines.append(header_str)

    sep_str = "|"
    for i in range(num_cols):
        width = col_widths[i]
        if alignments[i]:
            # The requirement says "use ---: in the separator row"
            # and "separator row dashes should fill the full column width"
            # If width is 3, it should be "---:"? No, that's 4 chars.
            # "fill the full column width" means if width is 5, it's "----:"
            dashes = "-" * (width)
            sep_str += f" {dashes}: |"
        else:
            dashes = "-" * width
            sep_str += f" {dashes} |"
    formatted_lines.append(sep_str)

    for row in data_rows:
        row_str = "|"
        for i in range(num_cols):
            val = row[i] if i < len(row) else ""
            width = col_widths[i]
            if alignments[i]:
                row_str += f" {val.rjust(width)} |"
            else:
                row_str += f" {val.ljust(width)} |"
        formatted_lines.append(row_str)

    return formatted_lines

def main():
    try:
        with open('workspace/input.md', 'r') as f:
            lines = f.readlines()
    except FileNotFoundError:
        return

    output = []
    table_buffer = []
    in_table = False

    for line in lines:
        stripped = line.strip()
        # A table line must contain at least one |
        if '|' in stripped:
            in_table = True
            table_buffer.append(line)
        else:
            if in_table:
                output.extend(format_table(table_buffer))
                table_buffer = []
                in_table = False
            output.append(line.rstrip('\n'))

    if in_table:
        output.extend(format_table(table_buffer))

    with open('workspace/formatted.md', 'w') as f:
        f.write('\n'.join(output) + '\n')

if __name__ == "__main__":
    main()

