import json
import os

def generate_changelog():
    input_path = 'workspace/commits.jsonl'
    output_path = 'workspace/CHANGELOG.md'

    if not os.path.exists(input_path):
        print(f"Error: {input_path} not found.")
        return

    commits_by_type = {
        'feat': [],
        'fix': [],
        'docs': [],
        'chore': []
    }

    type_mapping = {
        'feat': '## Features',
        'fix': '## Bug Fixes',
        'docs': '## Documentation',
        'chore': '## Chores'
    }

    with open(input_path, 'r') as f:
        for line in f:
            if not line.strip():
                continue
            commit = json.loads(line)
            ctype = commit.get('type')
            if ctype in commits_by_type:
                commits_by_type[ctype].append(commit)

    changelog_lines = ["# Changelog", ""]

    for ctype in ['feat', 'fix', 'docs', 'chore']:
        commits = commits_by_type[ctype]
        if commits:
            changelog_lines.append(type_mapping[ctype])
            for c in commits:
                line = f"- {c['message']} ({c['hash']}) - {c['author']}"
                changelog_lines.append(line)
            changelog_lines.append("") # Blank line after section

    # Remove trailing blank line if exists
    if changelog_lines[-1] == "":
        changelog_lines.pop()

    with open(output_path, 'w') as f:
        f.write("\n".join(changelog_lines) + "\n")

if __name__ == "__main__":
    generate_changelog()

